import json
d=json.load(open('.claude/jjm/jjg_gallops.json'))
def find(o,path=()):
    if isinstance(o,dict):
        for k,v in o.items():
            if k=="₢BMAAM" and isinstance(v,dict) and "jjgpn_tacks" in v:
                yield v["jjgpn_tacks"]
            yield from find(v,path+(k,))
        return
    if isinstance(o,list):
        for i,v in enumerate(o): yield from find(v,path+(i,))
for tacks in find(d):
    print("num tacks:",len(tacks))
    for i,t in enumerate(tacks):
        txt=t.get("jjgtn_text","")
        first=txt.splitlines()[0] if txt else "(empty)"
        print(f"  [{i}] ts={t.get('jjgtn_ts')} state={t.get('jjgtn_state')} len={len(txt)} :: {first[:60]}")
