def walk(o):
    if isinstance(o,dict):
        for k,v in o.items():
            if isinstance(v,dict) and "jjgpn_tacks" in v:
                ts=[t.get("jjgtn_ts","") for t in v["jjgpn_tacks"]]
                if ts!=sorted(ts,reverse=True):
                    print(f"  OUT-OF-ORDER {k}: {ts}")
                dup=[x for x in set(ts) if ts.count(x)>1]
                if dup: print(f"  DUP-TS {k}: {dup}")
            walk(v)
    elif isinstance(o,list):
        for v in o: walk(v)
walk(d)
